sys_ws_operation.operation_script:
(function process(request, response) {
  var utils = new AlationUtils();

  var qs = request.queryParams || {};
  var qRaw = (qs.q || '').toString();
  var q = qRaw ? qRaw.trim().toLowerCase() : '';
  var startAt = parseInt(qs.startAt, 10); if (isNaN(startAt) || startAt < 0) startAt = 0;
  var maxResults = parseInt(qs.maxResults, 10); if (isNaN(maxResults) || maxResults < 1) maxResults = 25;
  if (maxResults > 100) maxResults = 100;

  var lang = gs.getSession().getLanguage() || 'en';

  var choiceRec = new GlideRecord('sys_choice');
  choiceRec.addQuery('name', 'incident');
  choiceRec.addQuery('element', 'category');
  choiceRec.addQuery('inactive', false);
  choiceRec.addQuery('language', lang);
  choiceRec.orderBy('sequence');
  choiceRec.orderBy('label');
  choiceRec.query();

  var results = [];
  var seen = 0;
  while (choiceRec.next()) {
    var value = String(choiceRec.value || '');
    var label = String(choiceRec.label || value);
    if (q) {
      var hay = (label + ' ' + value).toLowerCase();
      if (hay.indexOf(q) === -1) continue;
    }
    if (seen++ < startAt) continue;
    results.push({ value: value, label: label });
    if (results.length >= maxResults) break;
  }

  var nextStartAt = results.length === maxResults ? (startAt + results.length) : null;

  return utils.ok(response, 200, {
    startAt: startAt,
    maxResults: maxResults,
    nextStartAt: nextStartAt,
    results: results
  });
})(request, response);
